command:
const speaker = ChatMessage.getSpeaker();
const actor =
	canvas.tokens?.controlled?.find((t) => t.actor?.testUserPermission?.(game.user, "OWNER"))?.actor ??
	canvas.tokens?.controlled?.[0]?.actor ??
	(speaker.actor ? game.actors.get(speaker.actor) : null) ??
	(!game.user.isGM ? game.actors.contents.find((a) => a.type === "agent" && a.testUserPermission?.(game.user, "OWNER")) : null);
if (!actor) return ui.notifications.warn(game.i18n.localize("op.noActorSelected"));

const skillOptions = Object.entries(CONFIG.op.skills)
	.map(([key, label]) => `<option value="${key}">${game.i18n.localize(label)}</option>`)
	.join("");
const content = `
	<div class="form-group"><label>${game.i18n.localize("op.macroSkillLabel")}</label><select name="skill">${skillOptions}</select></div>
	<div class="form-group"><label>${game.i18n.localize("op.macroDtOptional")}</label><input type="number" name="target" placeholder="${game.i18n.localize("op.macroDtPlaceholder")}" min="0" /></div>
`;

const input = await foundry.applications.api.DialogV2.prompt({
	window: { title: game.i18n.localize("op.macroRollSkillTitle") },
	content,
	ok: {
		label: game.i18n.localize("op.macroRollButton"),
		callback: (_event, button) => new FormDataExtended(button.form).object,
	},
});
if (!input || !input.skill) return;

const rollOptions = {};
if (input.target !== "" && input.target !== null && input.target !== undefined) {
	rollOptions.rolls = [{ options: { target: Number(input.target) } }];
}
actor.rollSkill({ skill: input.skill, ...rollOptions });
